// Time:  O(nlogn + nlogr), r is the range of positions
// Space: O(1)

class Solution {
public:
    int maxDistance(vector<int>& position, int m) {
        sort(begin(position), end(position));
        int left = 0, right = position.back() - position.front();
        while (left <= right) {
            const auto& mid = left + (right - left) / 2;
            if (!check(position, m, mid)) {
                right = mid - 1;
            } else {
                left = mid + 1;
            }
        }
        return right;
    }

private:
    bool check(const vector<int>& position, int m, int x) {
        int count = 1, prev = position[0];
        for (int i = 1; i < position.size(); ++i) {
            if (position[i] - prev >= x) {
                ++count;
                prev = position[i];
            }
        }
        return count >= m;
    }
};

# Time:  O(nlogn + nlogr), r is the range of positions
# Space: O(1)

class Solution(object):
    def maxDistance(self, position, m):
        """
        :type position: List[int]
        :type m: int
        :rtype: int
        """
        def check(position, m, x):
            count, prev = 1, position[0]
            for i in xrange(1, len(position)):
                if position[i]-prev >= x:
                    count += 1
                    prev = position[i]
            return count >= m

        position.sort()
        left, right = 1, position[-1]-position[0]
        while left <= right:
            mid = left + (right-left)//2
            if not check(position, m, mid):
                right = mid-1
            else:
                left = mid+1
        return right
